def generate_cache_key(prefix, *args, **kwargs):
    key_parts = [prefix]
    key_parts.extend(str(arg) for arg in args)
    key_parts.extend(f"{k}:{v}" for k, v in sorted(kwargs.items()))
    key_string = ':'.join(key_parts)
    return hashlib.md5(key_string.encode()).hexdigest()

def cache_result(prefix, ttl=300):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = generate_cache_key(prefix, *args, **kwargs)
            
            cached_data = memcache_client.get(cache_key)
            if cached_data is not None:
                return cached_data, True
            
            result = func(*args, **kwargs)
            
            memcache_client.set(cache_key, result, expire=ttl)
            
            return result, False
        return wrapper
    return decorator

def invalidate_cache(prefix, *args, **kwargs):
    cache_key = generate_cache_key(prefix, *args, **kwargs)
    memcache_client.delete(cache_key)

def cache_api_response(ttl=300):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            request_data = {
                'path': request.path,
                'method': request.method,
                'args': dict(request.args)
            }
            cache_key = generate_cache_key('api', json.dumps(request_data, sort_keys=True))
            
            cached_response = memcache_client.get(cache_key)
            if cached_response is not None:
                response_data, status_code = cached_response
                response = jsonify(response_data)
                response.headers['X-Cache'] = 'HIT'
                return response, status_code
            
            result = func(*args, **kwargs)
            
            if isinstance(result, tuple):
                response_obj, status_code = result
            else:
                response_obj = result
                status_code = 200
            
            if hasattr(response_obj, 'get_json'):
                response_data = response_obj.get_json()
            else:
                response_data = response_obj
            
            memcache_client.set(cache_key, (response_data, status_code), expire=ttl)
            
            response = jsonify(response_data)
            response.headers['X-Cache'] = 'MISS'
            return response, status_code
        return wrapper
    return decorator

